const i = $input.first().json || {};
const h = i.headers || {};
const cookieHeader = (h.cookie ?? h.Cookie ?? '').toString();
const m = cookieHeader.match(/(?:^|;\s*)ba_session=([^;]+)/);
const session_token = m ? m[1] : '';
const origin = (h.origin ?? h.Origin ?? '').toString().trim();
const allowedOrigins = ["https://barberagency-barberagency.gymh5g.easypanel.host","https://panel-de-barberia.gymh5g.easypanel.host"];
const cors_origin = allowedOrigins.includes(origin) ? origin : allowedOrigins[0];
return [{ json: { session_token, cors_origin } }];

const i = $input.first().json || {};
let cors_origin = 'https://barberagency-barberagency.gymh5g.easypanel.host';
try {
  const source = $('Code - parse cookie').first().json || {};
  cors_origin = source.cors_origin || cors_origin;
} catch (_) {}
const auth_ok = !i.error && !!i.payload?.user_id;
const user_id = auth_ok ? Number(i.payload.user_id) : 0;
const message = auth_ok ? '' : 'Sesion no valida';
return [{ json: { auth_ok, user_id, message, cors_origin } }];

const i = $input.first().json || {};
const ok = !!i.ok;
const status_code = Number(i.status_code ?? (ok ? 200 : 401));
const clearCookie = 'ba_session=; Path=/; Max-Age=0; HttpOnly; Secure; SameSite=Lax';

const nombreRaw = (i.nombre ?? '').toString().trim();
const parts = nombreRaw ? nombreRaw.split(/\s+/).filter(Boolean) : [];
const apellido = parts.length > 1 ? parts.slice(1).join(' ') : null;
const barberias = Array.isArray(i.barberias) ? i.barberias : [];
const currentBarberia = i.current_barberia && typeof i.current_barberia === 'object'
  ? i.current_barberia
  : null;
const barberiasCount = Number(i.barberias_count ?? barberias.length ?? 0);

let next_action = 'login';
if (ok) {
  if (barberiasCount <= 0) next_action = 'create_barberia';
  else if (barberiasCount === 1) next_action = 'open_dashboard';
  else next_action = 'choose_barberia';
}

return [{
  json: {
    status_code,
    response_body: ok
      ? {
          ok: true,
          user_id: i.user_id,
          email: i.email,
          nombre: nombreRaw,
          apellido,
          plan_id: i.plan_id ?? null,
          puede_crear_barberia: !!i.puede_crear_barberia,
          user: {
            id: i.user_id,
            email: i.email,
            nombre: nombreRaw,
            apellido,
          },
          current_barberia: currentBarberia,
          barberias,
          barberias_count: barberiasCount,
          next_action,
        }
      : {
          ok: false,
          message: (i.message ?? 'Sesion no valida').toString(),
          next_action,
        },
    set_cookie: ok ? '' : clearCookie,
    cors_origin: i.cors_origin || 'https://barberagency-barberagency.gymh5g.easypanel.host',
  },
}];

